/* ============================================
   PHÚC AN Dashboard Styles
   ============================================ */

/* Background page */
body {
  background-color: #F5F6F8;
}

/* ============================================
   TOP BAR
   ============================================ */
.top-bar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: 100%;
  margin-bottom: 0;
  padding: 0;
  background: transparent;
}

.top-bar-left {
  flex: 1;
}

.top-bar-center {
  flex: 1;
  display: flex;
  justify-content: center;
  max-width: 480px;
  margin: 0 auto;
}

.top-bar-search {
  display: flex;
  align-items: center;
  gap: 8px;
  background: #F3F4F6;
  border-radius: 9999px;
  padding: 8px 16px;
  width: 100%;
  max-width: 400px;
}

.top-bar-search-icon {
  color: #9CA3AF;
  font-size: 16px;
  flex-shrink: 0;
}

