  color: #9CA3AF;
}

.top-bar-right {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: 14px;
  padding-right: 4px;
}

.top-bar-bell {
  font-size: 20px;
  color: #6B7280;
  cursor: pointer;
}

/* ============================================
   DASHBOARD CONTENT HEADER
   ============================================ */
.dashboard-content-header {
  display: flex;
  flex-direction: column;
  gap: 0;
  padding-bottom: 20px;
  border-bottom: 1px solid #F3F4F6;
  margin-bottom: 24px;
}

.dashboard-content-title {
  font-size: 26px;
  font-weight: 700;
  color: #1F2937;
  margin: 0 0 16px 0;
  letter-spacing: -0.5px;
  white-space: nowrap;
