}

.dashboard-content-controls {
  display: flex;
  align-items: center;
  gap: 12px;
  flex-wrap: wrap;
  margin-bottom: 20px;
}

/* Export icon button */
.export-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 38px;
  height: 38px;
  border-radius: 8px;
  background: #EFF6FF;
  border: 1px solid #DBEAFE;
  color: #1D4ED8;
